INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('customs-f19eb2bd-moex-00267', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '關於船舶應急程序之初始動作，下列敘述何者錯誤？', '["人員落水當下，應轉滿舵向落水人員一側，並釋放該側附燈光及煙霧信號救生圈，並以汽笛鳴放三長 聲，高喊「人員落水」", "人員落水當下，使用單回轉法（Singleturn）可最快速將本船駛回落水人員地點", "船舶火災發生時，應先嘗試使用滅火設備即時撲滅火源，倘若無法有效撲滅時，再通知值班人員發出火 災信號", "船舶火災信號為鳴汽笛或警鈴至少連續10秒鐘並輔以廣播設備通知全體人員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00268', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '我國船舶法對於船舶檢查的規定，下列敘述何者錯誤？', '["船舶檢查分為特別檢查、定期檢查與臨時檢查", "客船與貨船船齡超過20年時，核發與換發特別檢查證書的有效期限以5年為限", "船舶之定期檢查應於特別檢查後，每屆滿一年之前後3個月內，申請施行定期檢查", "船舶遭遇海難或適航性發生疑義時，應申請實施臨時檢查"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00269', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '關於船體保養船舶進塢（dry-docked）的規範，下列何者錯誤？', '["海上人命安全國際公約（SOLAS）規範，船舶任意每5年間隔內應進塢2次", "海上人命安全國際公約（SOLAS）規範，船舶進塢的間隔時間不得超過30個月", "驗船協會（Classification societies）對於船舶進塢的時間間隔要求，通常與海上人命安全國際公約 （SOLAS）一致", "船舶進塢的主要目的是針對水線以下的船體做檢查、修理、保養與清除海生物附著等工作"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00270', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '若A點經度是15836.0W，B點經度為16712.0E，則兩點之間的中央子午線經度為何？', '["17542.0W", "17836.0W", "17606.0E", "17412.0E"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00271', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '關於浮標系統中的基點標誌（Cardinalmark），下列何者錯誤？', '["國際助航設備與燈塔協會（IALA），A系統與B系統的基點標誌規範內容相同", "東基點是黑色浮標，但其中夾有一寬水平黃色帶，柱狀或圓柱狀", "東基點的頂標為底座相連的兩個尖錐，船舶應保持東基點浮標在其東側通過危險區域", "東基點浮標的燈光為白色，燈質為VQ(3)5S，或Q(3)10S"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00272', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '目前下列何種航海圖書不是由我國海軍大氣海洋局所出版？', '["海圖圖例", "潮汐表", "航行指南", "中華民國燈表"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00273', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '關於潮汐與潮流的名詞定義，下列何者錯誤？', '["潮汐日（Tidalday），指月球連續兩次通過地球同一子午線的時間", "半日潮（Semi-diurnaltide），指每一潮汐日中有兩次高潮與兩次低潮的現象", "憩潮（Standtide），指往復潮流於流向改變之期間有一短暫之時間沒有水流之移動現象", "迴旋潮流（Rotarytidalcurrent），指因潮汐作用所產生的潮流，在離岸稍遠處，潮流方向不受障礙物影 響所產生"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00274', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '時差（Equationoftime）的定義係為下列何者？', '["當地視太陽時與格林威治視太陽時的差值", "當地經度換算成時間單位", "在格林威治子午線之恆星時間與區域時間的差值", "視太陽時減去平均太陽時的差值"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00275', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '關於電羅經（Gyrocompass）之動作原理，下列敘述何者錯誤？', '["迴轉儀慣性（Gyroscopicinertia）保持旋轉中之轉輪於原來平面上，抗拒任何欲改變其旋轉平面之外力", "將外力施於旋轉中之迴轉儀軸，該軸依外力所施方向轉動，稱為偏移（Precession）", "水平地球運轉率（Horizontalearthrate）導致迴轉儀產生相對於地球之俯仰運動", "垂直地球運轉率（Verticalearthrate）導致迴轉儀產生相對於地球之方位運動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00276', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '下列那一種測速儀（Speedlog），其測速顯示可設定為對地速度（speedovertheground）？', '["水壓式測速儀（Pitot-staticlog）", "推進式測速儀（Impellertypelog）", "電磁式測速儀（EMlog）", "都卜勒測速儀（Dopplerlog）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL)
